	// Beego ORM maps snake_case aliases to CamelCase struct fields
	sql := fmt.Sprintf(`
		SELECT u.display_name, a.action_type, 
		       COUNT(*) as total_actions, 
		       SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count, 
		       AVG(a.duration_ms) as avg_duration
		FROM user_activity a
		JOIN user_profile u ON a.user_id = u.id
		WHERE u.username IN (%s)
		AND a.created_at BETWEEN ? AND ?
	`, strings.Join(placeholders, ","))

	args = append(args, startDate, endDate)

	if actionTypeFilter != "" {
		sql += " AND a.action_type = ?"
		args = append(args, actionTypeFilter)
	}

	sql += " GROUP BY u.display_name, a.action_type"

	var report []UserActivitySummary
	if _, err := o.Raw(sql, args...).QueryRows(&report); err != nil {
		return nil, err
	}

	return report, nil
}

// GenerateDepartmentReport creates a summary report grouped by a specified field.
// Parameters:
// - o: the ORM instance
// - departments: list of department names to include (filter by department IN (...))
// - groupByField: which field to group by, must be one of: "department", "role", "display_name"
//
// Returns a slice of maps with keys: "group_value" (the grouped field value), "user_count", "total_activities"
func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	// Validate groupByField to prevent SQL injection since it's used as a column name
	allowedFields := map[string]bool{
		"department":   true,
		"role":         true,
		"display_name": true,
	}
	if !allowedFields[groupByField] {
		return nil, errors.New("invalid group by field")
	}

	// Build placeholders for the IN clause
	placeholders := make([]string, len(departments))
	args := make([]interface{}, 0, len(departments))
	for i, d := range departments {
		placeholders[i] = "?"
		args = append(args, d)
	}

	// Construct SQL
	// LEFT JOIN is used to count users even if they have no activities (total_activities will be 0)
	sql := fmt.Sprintf(`
		SELECT u.%s as group_value,
		       COUNT(DISTINCT u.id) as user_count,
		       COUNT(a.id) as total_activities
		FROM user_profile u
		LEFT JOIN user_activity a ON u.id = a.user_id
		WHERE u.department IN (%s)
		GROUP BY u.%s
	`, groupByField, strings.Join(placeholders, ","), groupByField)

	var results []orm.Params
	if _, err := o.Raw(sql, args...).Values(&results); err != nil {
		return nil, err
	}

	// Convert []orm.Params to []map[string]interface{}
	// orm.Params is a map[string]interface{} alias
	report := make([]map[string]interface{}, len(results))
	for i, r := range results {
		report[i] = map[string]interface{}(r)
	}

	return report, nil
}

