	}

	var args []interface{}
	whereClause := "1=1"

	// Build filter for departments if provided
	if len(departments) > 0 {
		placeholders := make([]string, len(departments))
		for i, d := range departments {
			placeholders[i] = "?"
			args = append(args, d)
		}
